     * A rule that replaces XXX with YYY in comments
     */
    private class ReplaceXWithYRule :
        Rule(
            ruleId = RuleId("test:replace-x-with-y"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
