        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.EOL_COMMENT && node.text.contains("YYY")) {
                emit(node.startOffset, "Found YYY, should be ZZZ", true)
                if (autoCorrect) {
                    (node as LeafPsiElement).rawReplaceWithText(node.text.replace("YYY", "ZZZ"))
                }
            }
        }
    }

    /**
     * A rule that always makes changes to test the maximum rerun limit
     */
    private class CountingRule(val onFormat: () -> Unit) :
        Rule(
            ruleId = RuleId("test:counting-rule"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            // Only modify INFINITE markers in comments and keep adding more characters
            if (node.elementType == ElementType.EOL_COMMENT && node.text.contains("INFINITE")) {
                emit(node.startOffset, "Always autocorrect", true)
                if (autoCorrect) {
                    onFormat()
                    // Keep modifying the comment to trigger more reruns
                    (node as LeafPsiElement).rawReplaceWithText(node.text + "X")
                }
            }
        }
    }"}

