    fun `Given code that would cause infinite rewrites, limit to 3 reruns`() {
        // This test ensures the maximum of 3 reruns prevents infinite loops
        var formatRunCount = 0
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { CountingRule { formatRunCount++ } },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                // INFINITE
                fun foo() {}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        // Should run exactly 3 times (initial + 2 reruns = 3 total, but we limited to max 3 runs)
        // The CountingRule will attempt to fix infinitely, but we stop at 3 runs
        assertThat(formatRunCount).isLessThanOrEqualTo(3)
    }", "new_string": "    @Test
    fun `Given code that would cause infinite rewrites, limit to 3 reruns`() {
        // This test ensures the maximum of 3 reruns prevents infinite loops
        var formatRunCount = 0
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { CountingRule { formatRunCount++ } },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                // INFINITE
                fun foo() {}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        // Should run exactly 3 times (initial + 2 reruns = 3 total, but we limited to max 3 runs)
        // The CountingRule will attempt to fix infinitely, but we stop at 3 runs
        assertThat(formatRunCount).isEqualTo(3)
        // The comment should have been appended with 'X' three times
        assertThat(formatted).contains("// INFINITEXXX")
    }"}

