        LOGGER.debug { "Starting with formatting file '${code.fileNameOrStdin()}'" }

        val hasUTF8BOM = code.content.startsWith(UTF8_BOM)
        var currentCode = code
        var ruleExecutionContext = createRuleExecutionContext(this, currentCode)

        var tripped = false
        var mutated = false
        val errors = mutableSetOf<Pair<LintError, Boolean>>()

        // Repeat format step until no more errors are found which can be auto-corrected.
        // To prevent infinite reruns, limit to 3 reruns maximum.
        var formatRun = 0
        val maxFormatRuns = 3

        do {
            if (formatRun > 0) {
                LOGGER.debug { "Rerunning format for file '${code.fileNameOrStdin()}' (run ${formatRun + 1})" }
                // Get the current formatted content and recreate the execution context
                val formattedContent = ruleExecutionContext
                    .rootNode
                    .text
                    .replace("\n", ruleExecutionContext.determineLineSeparator(code.content))
                // Create a new Code object with the formatted content while preserving file path information
                currentCode = Code.fromSnippet(formattedContent, currentCode.script)
                ruleExecutionContext = createRuleExecutionContext(this, currentCode)
                // Clear errors from previous runs as we'll collect them again
                errors.clear()
            }

            var mutatedInCurrentRun = false
            val visitorProvider = VisitorProvider(ruleExecutionContext.ruleProviders)
            visitorProvider
                .visitor()
                .invoke { rule ->
                    ruleExecutionContext.executeRule(rule, true) { offset, errorMessage, canBeAutoCorrected ->
                        tripped = true
                        if (canBeAutoCorrected) {
                            mutated = true
                            mutatedInCurrentRun = true
                            /**
                             * Rebuild the suppression locator after each change in the AST as the offsets of the
                             * suppression hints might have changed.
                             */
                            ruleExecutionContext.rebuildSuppressionLocator()
                        }
                        val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                        errors.add(
                            Pair(
                                LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected),
                                // It is assumed that a rule that emits that an error can be autocorrected, also
                                // does correct the error.
                                canBeAutoCorrected,
                            ),
                        )
                        // In trace mode report the violation immediately. The order in which violations are actually found might be different
                        // from the order in which they are reported. For debugging purposes it cn be helpful to know the exact order in which
                        // violations are being solved.
                        LOGGER.trace {
                            "Format violation: ${code.fileNameOrStdin()}:$line:$col: $errorMessage (${rule.ruleId})" +
                                canBeAutoCorrected.ifFalse { " [cannot be autocorrected]" }
                        }
                    }
                }

            formatRun++

            // Continue looping if mutations were made and we haven't exceeded the max runs
        } while (mutatedInCurrentRun && formatRun < maxFormatRuns)

        if (tripped) {
            val visitorProvider = VisitorProvider(ruleExecutionContext.ruleProviders)
            visitorProvider
                .visitor()
                .invoke { rule ->
                    ruleExecutionContext.executeRule(
                        rule,
                        false,
                    ) { offset, errorMessage, canBeAutoCorrected ->
                        val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                        errors.add(
                            Pair(
                                LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected),
                                // It is assumed that a rule only corrects an error after it has emitted an
                                // error and indicating that it actually can be autocorrected.
                                false,
                            ),
                        )
                    }
                }
        }

        errors
            .sortedWith { (l), (r) -> if (l.line != r.line) l.line - r.line else l.col - r.col }
            .forEach { (e, corrected) -> callback(e, corrected) }

        if (!mutated) {
            return code.content
        }

        val formattedCode =
            ruleExecutionContext
                .rootNode
                .text
                .replace("\n", ruleExecutionContext.determineLineSeparator(code.content))
        return if (hasUTF8BOM) {
            UTF8_BOM + formattedCode
        } else {
            formattedCode
        }.also {
            LOGGER.debug("Finished with formatting file '${code.fileNameOrStdin()}'")
        }
    }"}

