                    setOf(
                        RuleProvider { AddWhitespaceRule() },
                        RuleProvider { RemoveWhitespaceRule() },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                fun foo(){}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        // The final result should have the correct formatting
        assertThat(formatted).isEqualTo(
            """
            fun foo() {}
            """.trimIndent(),
        )
    }

    @Test
    fun `Given a code that needs exactly one reformat pass`() {
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { SimpleWhitespaceRule() },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                fun foo(){  }
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        assertThat(formatted).isEqualTo(
            """
            fun foo() {}
            """.trimIndent(),
        )
    }

    @Test
    fun `Given code with no violations, format should not modify it`() {
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { SimpleWhitespaceRule() },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                fun foo() {}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        assertThat(formatted).isEqualTo(
            """
            fun foo() {}
            """.trimIndent(),
        )
    }

    /**
     * A rule that adds whitespace after opening braces
     */
    private class AddWhitespaceRule :
        Rule(
            ruleId = RuleId("test:add-whitespace"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.LBRACE) {
                val nextNode = node.treeNext
                if (nextNode != null && nextNode.text != " " && nextNode.elementType != ElementType.WHITE_SPACE) {
                    emit(node.startOffset, "Missing space after opening brace", true)
                    if (autoCorrect) {
                        (node as LeafPsiElement).rawInsertAfterMe(LeafPsiElement(ElementType.WHITE_SPACE, " "))
                    }
                }
            }
        }
    }

    /**
     * A rule that removes extra whitespace before closing braces
     */
    private class RemoveWhitespaceRule :
        Rule(
            ruleId = RuleId("test:remove-whitespace"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.RBRACE) {
                val prevNode = node.treePrev
                if (prevNode != null && prevNode.elementType == ElementType.WHITE_SPACE && prevNode.text == " ") {
                    val beforeSpace = prevNode.treePrev
                    if (beforeSpace != null && beforeSpace.elementType == ElementType.WHITE_SPACE) {
                        emit(prevNode.startOffset, "Extra whitespace before closing brace", true)
                        if (autoCorrect) {
                            prevNode.treeParent.removeChild(prevNode)
                        }
                    }
                }
            }
        }
    }

    /**
     * A simple rule that removes extra whitespace in braces
     */
    private class SimpleWhitespaceRule :
        Rule(
            ruleId = RuleId("test:simple-whitespace"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.WHITE_SPACE && node.text.length > 1) {
                val parent = node.treeParent
                val nextSibling = node.treeNext
                if (parent != null && nextSibling?.elementType == ElementType.RBRACE) {
                    emit(node.startOffset, "Too much whitespace", true)
                    if (autoCorrect) {
                        (node as LeafPsiElement).rawReplaceWithText(" ")
                    }
                }
            }
        }
    }
}
