import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
import org.junit.jupiter.api.Test

/**
 * Tests to verify that the format function reruns until no more auto-correctable errors are found,
 * with a maximum of 3 reruns to prevent infinite loops.
 */
class ReformatTest {
    @Test
    fun `Given code with no violations, format should not modify it`() {
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { TestRule() },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                fun foo() {}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        assertThat(formatted).isEqualTo(
            """
            fun foo() {}
            """.trimIndent(),
        )
    }

    @Test
    fun `Given a code that requires multiple format passes due to rule execution order`() {
        // This test verifies that formatting reruns when rules create situations that
        // require another pass. The ReplaceXWithYRule will replace 'XXX' with 'YYY',
        // then the ReplaceYWithZRule will replace 'YYY' with 'ZZZ' in the next pass.
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { ReplaceXWithYRule() },
                        RuleProvider { ReplaceYWithZRule() },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                // XXX
                fun foo() {}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        // After multiple passes, XXX -> YYY -> ZZZ
        assertThat(formatted).isEqualTo(
            """
            // ZZZ
            fun foo() {}
            """.trimIndent(),
        )
    }

    @Test
    fun `Given code that would cause infinite rewrites, limit to 3 reruns`() {
        // This test ensures the maximum of 3 reruns prevents infinite loops
        var formatRunCount = 0
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { CountingRule { formatRunCount++ } },
                    ),
            )

        val code =
            Code.fromSnippet(
                """
                // INFINITE
                fun foo() {}
                """.trimIndent(),
            )

        val formatted = ktLintRuleEngine.format(code)

        // Should run exactly 3 times (initial + 2 reruns = 3 total, but we limited to max 3 runs)
        // The CountingRule will attempt to fix infinitely, but we stop at 3 runs
        assertThat(formatRunCount).isLessThanOrEqualTo(3)
    }

    /**
     * A test rule that does nothing - used to verify no-change scenarios
     */
    private class TestRule :
        Rule(
            ruleId = RuleId("test:test-rule"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            // No-op
        }
    }

    /**
     * A rule that replaces XXX with YYY in comments
     */
    private class ReplaceXWithYRule :
        Rule(
            ruleId = RuleId("test:replace-x-with-y"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.EOL_COMMENT && node.text.contains("XXX")) {
                emit(node.startOffset, "Found XXX, should be YYY", true)
                if (autoCorrect) {
                    (node as LeafPsiElement).rawReplaceWithText(node.text.replace("XXX", "YYY"))
                }
            }
        }
    }

    /**
     * A rule that replaces YYY with ZZZ in comments
     */
    private class ReplaceYWithZRule :
        Rule(
            ruleId = RuleId("test:replace-y-with-z"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.EOL_COMMENT && node.text.contains("YYY")) {
                emit(node.startOffset, "Found YYY, should be ZZZ", true)
                if (autoCorrect) {
                    (node as LeafPsiElement).rawReplaceWithText(node.text.replace("YYY", "ZZZ"))
                }
            }
        }
    }

    /**
     * A rule that always makes changes to test the maximum rerun limit
     */
    private class CountingRule(val onFormat: () -> Unit) :
        Rule(
            ruleId = RuleId("test:counting-rule"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            // Only modify INFINITE markers in comments and keep adding more characters
            if (node.elementType == ElementType.EOL_COMMENT && node.text.contains("INFINITE")) {
                emit(node.startOffset, "Always autocorrect", true)
                if (autoCorrect) {
                    onFormat()
                    // Keep modifying the comment to trigger more reruns
                    (node as LeafPsiElement).rawReplaceWithText(node.text + "X")
                }
            }
        }
    }"}

